<template>
	<view class="page">
		<scroll-view scroll-y class="detail-scroll">
			<!-- 学生信息 -->
			<view class="student-card">
				<view class="student-row">
					<text class="student-id">{{ order.studentId }}</text>
					<text class="student-name">{{ order.studentName }}</text>
				</view>
				<text class="student-class">{{ order.className }}</text>
				<text class="student-time">{{ order.createTime }}</text>
			</view>

			<!-- 原始问题 -->
			<view class="section">
				<text class="section-label">学生原始问题</text>
				<text class="section-text">{{ order.question }}</text>
			</view>

			<!-- AI自动回复 -->
			<view class="section ai-reply">
				<text class="section-label">AI自动回复</text>
				<text class="section-text">{{ order.aiReply }}</text>
			</view>

			<!-- 历史对话 -->
			<view class="section">
				<text class="section-label">历史对话记录</text>
				<view class="chat-history">
					<view
						class="chat-msg"
						v-for="(msg, i) in order.chatHistory"
						:key="i"
						:class="{ 'msg-self': msg.role === 'student' }"
					>
						<text class="msg-content">{{ msg.content }}</text>
					</view>
				</view>
			</view>

			<!-- 问题标签 -->
			<view class="section">
				<text class="section-label">问题标签</text>
				<view class="tag-list">
					<view
						class="tag-item"
						v-for="(tag, i) in tags"
						:key="i"
						:class="{ active: selectedTag === tag }"
						@click="selectedTag = tag"
					>
						<text>{{ tag }}</text>
					</view>
				</view>
			</view>

			<!-- 回复区 -->
			<view class="section">
				<text class="section-label">回复</text>
				<textarea
					class="reply-input"
					v-model="replyContent"
					placeholder="请输入回复内容..."
				/>
				<view class="reply-attach" @click="attachImage">
					<text>  添加图片</text>
				</view>
			</view>

			<!-- 操作按钮 -->
			<view class="action-bar">
				<view class="action-btn accept" @click="handleAccept" v-if="order.status === 'pending'">
					<text>受理</text>
				</view>
				<view class="action-btn complete" @click="handleComplete">
					<text>完结</text>
				</view>
				<view class="action-btn reject" @click="handleReject" v-if="order.status !== 'completed'">
					<text>退回</text>
				</view>
			</view>

			<view class="bottom-space"></view>
		</scroll-view>
	</view>
</template>

<script>
import { api } from '@/common/utils/request.js'

export default {
	data() {
		return {
			orderId: '',
			order: {
				id: '',
				studentId: '',
				studentName: '',
				className: '',
				question: '',
				status: 'pending',
				createTime: '',
				aiReply: '',
				chatHistory: []
			},
			tags: [],
			selectedTag: '',
			replyContent: ''
		}
	},
	onLoad(options) {
		if (options.id) {
			this.orderId = options.id
			this.loadDetail(options.id)
		}
	},
	methods: {
		async loadDetail(id) {
			try {
				const res = await api.getOrderDetail(id)
				const data = res
				this.order = {
					id: data.id,
					studentId: data.studentId || '',
					studentName: data.studentName || '',
					className: data.className || '',
					question: data.question || '',
					status: data.status || 'pending',
					createTime: data.createTime || '',
					aiReply: data.aiReply || '',
					chatHistory: data.chatHistory || []
				}
				if (data.tags) {
					this.selectedTag = data.tags
				}
			} catch (e) {
				uni.showToast({ title: '加载详情失败', icon: 'none' })
			}
		},
		attachImage() {
			uni.chooseImage({
				count: 3,
				success: (res) => {
					uni.showToast({ title: '已选择' + res.tempFilePaths.length + '张图片', icon: 'success' })
				}
			})
		},
		async handleAccept() {
			try {
				await api.updateOrderStatus({ orderId: this.orderId, status: 'processing' })
				this.order.status = 'processing'
				uni.showToast({ title: '已受理', icon: 'success' })
			} catch (e) {
				uni.showToast({ title: '操作失败', icon: 'none' })
			}
		},
		handleComplete() {
			if (!this.replyContent.trim()) {
				uni.showToast({ title: '请先填写回复', icon: 'none' })
				return
			}
			uni.showModal({
				title: '确认完结',
				content: '确定完结此工单？',
				success: async (res) => {
					if (res.confirm) {
						try {
							await api.replyOrder({ orderId: this.orderId, content: this.replyContent })
							await api.updateOrderStatus({ orderId: this.orderId, status: 'completed' })
							this.order.status = 'completed'
							uni.showToast({ title: '已完结', icon: 'success' })
							setTimeout(() => uni.navigateBack(), 1500)
						} catch (e) {
							uni.showToast({ title: '操作失败', icon: 'none' })
						}
					}
				}
			})
		},
		handleReject() {
			uni.showModal({
				title: '确认退回',
				content: '确定退回此工单？',
				success: async (res) => {
					if (res.confirm) {
						try {
							await api.updateOrderStatus({ orderId: this.orderId, status: 'pending' })
							this.order.status = 'pending'
							uni.showToast({ title: '已退回', icon: 'success' })
						} catch (e) {
							uni.showToast({ title: '操作失败', icon: 'none' })
						}
					}
				}
			})
		}
	}
}
</script>

